parameters.text:
Sen bir kıdemli prompt mühendisisin. Aşağıdaki verileri analiz et ve mevcut prompt şablonlarını optimize et.

## Uygulanmamış Öğrenmeler (hata kayıtları):
{{ $json.learning_entries }}

## Mevcut Prompt Şablonları:
{{ $json.current_templates }}

## Görev:
1. Her hata türünü analiz et
2. İlgili prompt şablonunu belirle
3. Prompt'u iyileştir (daha net talimatlar, daha az hata riski)
4. Yeni prompt şablonu oluştur
5. İyileştirme nedenini açıkla

## Çıktı Formatı (JSON):
{
  "optimized_templates": [
    {
      "template_name": "mevcut_şablon_adı",
      "current_prompt": "mevcut_prompt",
      "optimized_prompt": "yeni_prompt",
      "reason": "iyileştirme_nedeni",
      "related_errors": ["hata_türü_1", "hata_türü_2"]
    }
  ],
  "new_templates": [
    {
      "template_name": "yeni_şablon_adı",
      "template_text": "yeni_prompt_metni",
      "template_type": "article|social|quality_check|learning",
      "category": "teknoloji|ekonomi|kultur|magazin|bilim|genel"
    }
  ],
  "summary": "Genel iyileştirme özeti"
}

parameters.jsCode:
// Optimizasyon sonuçlarını parse et
const results = [];

for (const item of $input.all()) {
  try {
    const aiOutput = item.json.output || item.json;
    const optimization = typeof aiOutput === 'string' ? JSON.parse(aiOutput) : aiOutput;

    // Optimize edilmiş şablonları işle
    if (optimization.optimized_templates) {
      for (const tmpl of optimization.optimized_templates) {
        results.push({
          json: {
            action: 'optimize',
            template_name: tmpl.template_name,
            current_prompt: tmpl.current_prompt,
            optimized_prompt: tmpl.optimized_prompt,
            reason: tmpl.reason,
            related_errors: JSON.stringify(tmpl.related_errors || [])
          }
        });
      }
    }

    // Yeni şablonları işle
    if (optimization.new_templates) {
      for (const tmpl of optimization.new_templates) {
        results.push({
          json: {
            action: 'create',
            template_name: tmpl.template_name,
            template_text: tmpl.template_text,
            template_type: tmpl.template_type,
            category: tmpl.category
          }
        });
      }
    }
  } catch (e) {
    console.error('Optimizasyon parse hatası:', e.message);
  }
}

console.log(`${results.length} şablon işlemi hazırlandı`);
return results;
